#include <queue>
#include <climits>

using namespace std;

// Helper function to check if a path exists from source to target with at most k heavy edges
// This uses a modified BFS/Dijkstra approach where the state is (node, heavy_edges_used)
bool can_reach(int n, const vector<vector<tuple<int, int, int>>>& adj, int source, int target, int k, int threshold) {
    // dist[i][j] stores the minimum number of edges to reach node i using exactly j heavy edges.
    // Since we are just checking reachability, a simple visited array or a distance array
    // where we prioritize fewer heavy edges is sufficient.
    // We use a 2D array: dist[node][heavy_count] = boolean (reachable)
    vector<vector<bool>> reachable(n, vector<bool>(k + 1, false));

    // Queue for BFS: stores {node, heavy_count}
    queue<pair<int, int>> q;

    q.push({source, 0});
    reachable[source][0] = true;

    while (!q.empty()) {
        auto [u, heavy_count] = q.front();
        q.pop();

        if (u == target) {
            return true;
        }

        for (const auto& edge : adj[u]) {
            int v = get<0>(edge);
            int weight = get<1>(edge);

            // Determine if the edge (u, v) is heavy or light based on threshold
            // Note: The adjacency list stores all edges. We need to check the weight.
            // In this specific implementation setup, we'll treat the edge weight in the adjacency list
            // as the actual weight w_i.

            int is_heavy = (weight > threshold) ? 1 : 0;
            int next_heavy_count = heavy_count + is_heavy;

            if (next_heavy_count <= k && !reachable[v][next_heavy_count]) {
                reachable[v][next_heavy_count] = true;
                q.push({v, next_heavy_count});
            }
        }
    }

    return false;
}

long long solve(long long n_ll, std::vector<std::vector<long long>> edges, long long source_ll, long long target_ll, long long k_ll) {
    int n = (int)n_ll;
    int source = (int)source_ll;
    int target = (int)target_ll;
    int k = (int)k_ll;

    if (source == target) {
        return 0;
    }

    // Collect all unique edge weights to define the search space for the threshold
    vector<int> weights;
    for (const auto& edge : edges) {
        int w = (int)edge[2];
        weights.push_back(w);
    }

    // The possible thresholds we need to test are:
    // 1. All existing edge weights (to distinguish between heavy/light)
    // 2. One less than each existing edge weight (to test the boundary condition)
    // 3. 0 (the minimum possible weight for a light edge if weights start >= 1)

    vector<int> test_thresholds;
    test_thresholds.push_back(0);
    for (int w : weights) {
        test_thresholds.push_back(w); // Threshold = w. Edges with weight w are light.
        if (w > 0) {
            test_thresholds.push_back(w - 1); // Threshold = w-1. Edges with weight w are heavy.
        }
    }

    // Sort and unique the test thresholds
    sort(test_thresholds.begin(), test_thresholds.end());
    test_thresholds.erase(unique(test_thresholds.begin(), test_thresholds.end()), test_thresholds.end());

    // Add a very large threshold to cover the case where all edges are light
    test_thresholds.push_back(1000000001); 
    sort(test_thresholds.begin(), test_thresholds.end());
    test_thresholds.erase(unique(test_thresholds.begin(), test_thresholds.end()), test_thresholds.end());


    // Build the adjacency list structure needed by can_reach
    // adj[u] stores list of {v, weight}
    vector<vector<tuple<int, int, int>>> adj(n);
    for (const auto& edge : edges) {
        int u = (int)edge[0];
        int v = (int)edge[1];
        int w = (int)edge[2];
        adj[u].emplace_back(v, w, 0); // {v, weight, placeholder}
        adj[v].emplace_back(u, w, 0); // {u, weight, placeholder}
    }

    // Binary search approach on the potential thresholds, but since the number of unique
    // weights is small (<= 10^3), iterating through sorted unique test thresholds is fine and simpler.

    long long min_threshold = -1;

    for (int t : test_thresholds) {
        if (can_reach(n, adj, source, target, k, t)) {
            // Since we are iterating through sorted thresholds, the first one that works is the minimum.
            // However, the test_thresholds list contains values derived from weights (w and w-1),
            // and the actual minimal threshold might be one not explicitly listed if it falls
            // between two weights, but given the problem constraints, if a threshold T works,
            // any T' > T where no edge weight falls in [T, T'] will also work, and we seek the minimum.

            // Let's check if we can find a smaller threshold by checking the previous one, or just trust the sorted order.

            // If we test T, and it works, the minimum threshold must be <= T. 
            // Since we iterate in increasing order, T is a candidate for the minimum.
            min_threshold = t;
            break; 
        }
    }

    // Re-evaluating the required minimum:
    // If T works, and T-1 does not work, then T is the minimum threshold.
    // If we only test T values derived from weights, we might miss T-1 if T-1 is not in the list.

    // A simpler approach: Binary Search over the range [0, max_weight]
    // Max weight is 10^9.

    long long low = 0;
    long long high = 1000000000; // Max possible weight
    long long ans = -1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;

        // Check if threshold 'mid' allows reaching the target
        if (can_reach(n, adj, source, target, k, (int)mid)) {
            // mid works, try for a smaller threshold
            ans = mid;
            high = mid - 1;
        } else {
            // mid does not work, need a larger threshold (to make more edges light)
            low = mid + 1;
        }
    }

    return ans;
}
