/**
 * Checks if a valid path exists from source to target using at most k heavy edges
 * given a specific threshold.
 *
 * This is solved using a modified BFS/Dijkstra approach where the state includes
 * the number of heavy edges used so far.
 * state: {node, heavy_edges_count}
 * dp[i][j] will store the minimum "cost" (in this simplified scenario, we just need reachability)
 * to reach node i using exactly j heavy edges. Since we only care about reachability,
 * we can use a boolean or a simpler distance metric if needed, but BFS/Dijkstra
 * structure is more appropriate here to find a path.
 *
 * Here, we use Dijkstra's structure, but since all edge weights in the context of
 * the state transition (which is just about count, not weight sum) are uniform (1 for heavy, 0 for light),
 * a 0-1 BFS or a standard BFS on the state space (node, heavy_count) is sufficient.
 *
 * State in queue: {heavy_count, node}
 */
bool check(int n, const vector<vector<vector<long long>>>& adj, int source, int target, int k, long long threshold) {
    // dist[i][j]: minimum "cost" (or just a flag) to reach node i using exactly j heavy edges.
    // Since we only care about reachability, we can use a boolean or treat it as shortest path on the state graph.
    // Let's use a 2D array to store the minimum number of heavy edges to reach node i.
    // However, since we are checking for <= k, let's use a boolean reachability matrix:
    // reachable[i][j] is true if node i is reachable using exactly j heavy edges.
    vector<vector<bool>> reachable(n, vector<bool>(k + 1, false));

    // Queue for BFS: {node, heavy_count}
    queue<pair<int, int>> q;

    // Start state
    q.push({source, 0});
    reachable[source][0] = true;

    while (!q.empty()) {
        pair<int, int> current = q.front();
        q.pop();
        int u = current.first;
        int heavy_count = current.second;

        if (u == target) {
            return true; // Found a path to target within the limit k
        }

        // Explore neighbors
        for (const auto& edge : adj[u]) {
            int v = edge[0];
            long long weight = edge[1];
            // The adjacency list structure here is slightly simplified based on the input format
            // Let's assume adj[u] stores {v, weight} for simplicity in this check function,
            // based on how we build it below.

            int next_heavy_count = heavy_count + (weight > threshold ? 1 : 0);

            if (next_heavy_count <= k && !reachable[v][next_heavy_count]) {
                reachable[v][next_heavy_count] = true;
                q.push({v, next_heavy_count});
            }
        }
    }

    // Check all possible counts up to k for the target
    for (int j = 0; j <= k; ++j) {
        if (reachable[target][j]) {
            return true;
        }
    }

    return false;
}

