    if (source == target) return 0;

    // 1. Collect all unique edge weights to define the search space for threshold
    vector<long long> weights;
    for (const auto& edge : edges) {
        weights.push_back(edge[2]);
    }
    // Include 0 as a possible minimum threshold if we are looking for the smallest non-negative integer
    weights.push_back(0); 
    sort(weights.begin(), weights.end());
    weights.erase(unique(weights.begin(), weights.end()), weights.end());

    // The possible candidates for the minimum threshold are the edge weights themselves,
    // and potentially 0 (which is implicitly included or checked).
