    // Binary search over the sorted unique weights + 0.
    // The search space is [0, max_weight].

    vector<long long> search_space;
    search_space.push_back(0);
    for (long long w : weights) {
        search_space.push_back(w);
    }
    sort(search_space.begin(), search_space.end());
    search_space.erase(unique(search_space.begin(), search_space.end()), search_space.end());

